import React, { useEffect, useRef, useState } from "react";
import "../styles/GeneralChat.css";
import therapistResponses from "../data/therapistResponses";

const GeneralChat = () => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [typing, setTyping] = useState(false);
  const endRef = useRef(null);

  useEffect(() => {
    setMessages([
      {
        sender: "bot",
        text: "Hi 👋 I’m your AI mental health assistant. I’m here to listen. How are you feeling today?",
      },
    ]);
  }, []);

  useEffect(() => {
    endRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, typing]);

  // ✅ FIXED EMOTION DETECTION
  const detectEmotion = (text) => {
    const t = text.toLowerCase();

    if (t.includes("angry") || t.includes("anger") || t.includes("mad"))
      return "anger";
    if (t.includes("stress") || t.includes("anxious"))
      return "anxiety";
    if (t.includes("sad") || t.includes("lonely"))
      return "sadness";
    if (t.includes("happy") || t.includes("good"))
      return "happiness";

    return "neutral";
  };

  const sendMessage = () => {
    if (!input.trim()) return;

    const userText = input.trim();
    setMessages((prev) => [...prev, { sender: "user", text: userText }]);
    setInput("");
    setTyping(true);

    const emotion = detectEmotion(userText);
    const replies = therapistResponses[emotion];
    const reply =
      replies[Math.floor(Math.random() * replies.length)];

    setTimeout(() => {
      setTyping(false);
      setMessages((prev) => [...prev, { sender: "bot", text: reply }]);
    }, 1400);
  };

  return (
    <div className="chat-page">
      <div className="chat-header">
        <h2>🧠 General Chat</h2>
        <span className="listening">❤️ Listening</span>
      </div>

      <div className="chat-body">
        {messages.map((msg, i) => (
          <div
            key={i}
            className={`chat-message ${msg.sender}`}
          >
            <div className="bubble">{msg.text}</div>
          </div>
        ))}

        {typing && (
          <div className="chat-message bot">
            <div className="typing">
              <span></span><span></span><span></span>
            </div>
          </div>
        )}

        <div ref={endRef} />
      </div>

      <div className="chat-input">
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Type how you feel..."
          onKeyDown={(e) => e.key === "Enter" && sendMessage()}
        />
        <button onClick={sendMessage}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
